// Split Google Calendar events array into individual n8n items
// and extract all fields needed for the reminder

const rawItems = items[0].json.items || [];

// Filter out cancelled events
const events = rawItems.filter(e => e.status !== 'cancelled');

if (events.length === 0) {
  return [];
}

return events.map(event => {
  const summary = event.summary || '';

  // Parse "[Service] - [Client Name]" format
  const dashIdx = summary.indexOf(' - ');
  const service = dashIdx !== -1 ? summary.substring(0, dashIdx).trim() : summary.trim();
  const clientName = dashIdx !== -1 ? summary.substring(dashIdx + 3).trim() : 'Client';

  // Parse description fields: Phone: xxx, Language: xx
  const description = event.description || '';

  const phoneMatch = description.match(/Phone:\s*([\d\+\-\s]+)/i);
  const phone = phoneMatch ? phoneMatch[1].replace(/[\s\-]/g, '').trim() : '';

  const langMatch = description.match(/Language:\s*([a-z]{2})/i);
  const language = langMatch ? langMatch[1].toLowerCase() : 'es';

  // Format start time as HH:MM
  let startTime = '';
  if (event.start && event.start.dateTime) {
    // dateTime is ISO string with offset, e.g. 2025-03-20T14:30:00-03:00
    const dt = new Date(event.start.dateTime);
    // Format in Montevideo timezone
    const timeStr = dt.toLocaleString('es-UY', {
      timeZone: 'America/Montevideo',
      hour: '2-digit',
      minute: '2-digit',
      hour12: false
    });
    startTime = timeStr;
  } else if (event.start && event.start.date) {
    startTime = 'all day';
  }

  return {
    json: {
      eventId: event.id || '',
      clientName,
      service,
      startTime,
      phone,
      language,
      rawSummary: summary
    }
  };
});

// Generate trilingual reminder message based on client language

const { clientName, service, startTime, phone, language } = $input.item.json;

if (!phone) {
  // No phone — skip this item by returning empty output signal
  return {
    json: {
      ...$input.item.json,
      reminderMessage: null,
      skip: true,
      skipReason: 'No phone number found in calendar event description'
    }
  };
}

let reminderMessage = '';

switch (language) {
  case 'ru':
    reminderMessage = `Добрый день, ${clientName}! Напоминаем, что сегодня у вас запись в AREA MOSA на ${service} в ${startTime}. Адрес: Кордон, Монтевидео. До встречи!`;
    break;

  case 'en':
    reminderMessage = `Hi ${clientName}! This is a reminder that you have an appointment at AREA MOSA for ${service} today at ${startTime}. Address: Cordon, Montevideo. See you there!`;
    break;

  case 'es':
  default:
    reminderMessage = `Hola ${clientName}! Te recordamos que hoy tienes cita en AREA MOSA para ${service} a las ${startTime}. Direccion: Cordon, Montevideo. Te esperamos!`;
    break;
}

return {
  json: {
    ...$input.item.json,
    reminderMessage,
    skip: false
  }
};
